import React, { useEffect, useState } from 'react';
import { notificationService } from '../../services/notificationService';
import { memberService } from '../../services/memberService';
import { useAuth } from '../../context/AuthContext';
import Modal from '../../components/Modal/Modal';
import './Notifications.css';

function Notifications() {
  const { user } = useAuth();
  const [notifications, setNotifications] = useState([]);
  const [members, setMembers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState({ open: false });
  const [form, setForm] = useState({ memberId: '', message: '' });
  const [error, setError] = useState('');

  const load = async () => {
    try {
      const [notifs, mems] = await Promise.all([
        notificationService.getByMember(user?.memberId),
        memberService.getAll(),
      ]);
      setNotifications(notifs);
      setMembers(mems);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { if (user?.memberId) load(); }, [user]);

  const handleCreate = async (e) => {
    e.preventDefault();
    setError('');
    try {
      await notificationService.create(form.memberId, form.message);
      setModal({ open: false });
      load();
    } catch {
      setError('Failed to send notification.');
    }
  };

  const handleMarkRead = async (id) => {
    await notificationService.markAsRead(id);
    load();
  };

  const handleDelete = async (id) => {
    await notificationService.delete(id);
    load();
  };

  const unreadCount = notifications.filter(n => !n.read).length;

  return (
    <div className="notifs-page fade-in">
      <div className="page-header">
        <div className="notifs-header">
          <div>
            <h1 className="page-title">Notifications</h1>
            <p className="page-subtitle">Due date reminders and library updates</p>
          </div>
          {unreadCount > 0 && (
            <div className="notifs-unread-badge">{unreadCount} unread</div>
          )}
        </div>
      </div>

      <div className="page-actions">
        <button className="btn btn--primary btn--md" onClick={() => { setForm({ memberId: user?.memberId || '', message: '' }); setModal({ open: true }); }}>
          + Send Notification
        </button>
      </div>

      {loading ? (
        <div className="loading-spinner" />
      ) : notifications.length === 0 ? (
        <div className="empty-state">
          <div className="empty-state__icon">🔔</div>
          <p className="empty-state__text">No notifications yet</p>
        </div>
      ) : (
        <div className="notifs-list">
          {notifications.map(n => (
            <div key={n.id || n.notification_id} className={`notif-card ${!n.read ? 'notif-card--unread' : ''}`}>
              <div className="notif-card__icon">{n.read ? '📭' : '📬'}</div>
              <div className="notif-card__content">
                <p className="notif-card__message">{n.message}</p>
                <span className="notif-card__time">
                  {n.createdAt || n.created_at || '—'}
                </span>
              </div>
              <div className="notif-card__actions">
                {!n.read && (
                  <button className="btn btn--teal btn--sm" onClick={() => handleMarkRead(n.id || n.notification_id)}>
                    Mark Read
                  </button>
                )}
                <button className="btn btn--danger btn--sm" onClick={() => handleDelete(n.id || n.notification_id)}>
                  Delete
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      <Modal isOpen={modal.open} onClose={() => setModal({ open: false })} title="Send Notification" size="sm">
        <form onSubmit={handleCreate}>
          {error && <div className="alert alert--error">{error}</div>}
          <div className="form-group">
            <label className="form-label">Member</label>
            <select className="form-select" value={form.memberId} onChange={e => setForm({ ...form, memberId: e.target.value })} required>
              <option value="">Select member...</option>
              {members.map(m => <option key={m.memberId} value={m.memberId}>{m.name}</option>)}
            </select>
          </div>
          <div className="form-group">
            <label className="form-label">Message</label>
            <textarea
              className="form-input notifs-textarea"
              rows={4}
              placeholder="Reminder: Your borrowed book is due in 3 days..."
              value={form.message}
              onChange={e => setForm({ ...form, message: e.target.value })}
              required
            />
          </div>
          <div className="form-actions">
            <button type="button" className="btn btn--secondary btn--md" onClick={() => setModal({ open: false })}>Cancel</button>
            <button type="submit" className="btn btn--primary btn--md">Send</button>
          </div>
        </form>
      </Modal>
    </div>
  );
}

export default Notifications;
